# Generate 3D-Atlantic times: 6-min steps from 2026-02-17 12:06
from datetime import timedelta
t3d_start = datetime(2026, 2, 17, 12, 6)
data_3d_raw_times = [t3d_start + timedelta(minutes=6*i) for i in range(len(data_3d_raw_values))]

# Parse 2D times
fmt = "%Y-%m-%d %H:%M"
t2d = [datetime.strptime(t, fmt) for t in data_2d_times]
v2d = data_2d_values

t3d = data_3d_raw_times
v3d = data_3d_raw_values

# --- Overlap window for comparison ---
t_start = max(t2d[0], t3d[0])
t_end   = min(t2d[-1], t3d[-1])

# --- Plot ---
fig, axes = plt.subplots(2, 1, figsize=(13, 8), sharex=False)
fig.suptitle("STOFS Water Level Forecast — Newport, RI (41.49°N, 71.31°W)", fontsize=13, fontweight="bold")

# ── Panel 1: both models on same axes (overlap period) ──────────────────────
ax1 = axes[0]

# Filter to overlap window
t2d_ov = [t for t in t2d if t_start <= t <= t_end]
v2d_ov = [v for t, v in zip(t2d, v2d) if t_start <= t <= t_end]
t3d_ov = [t for t in t3d if t_start <= t <= t_end]
v3d_ov = [v for t, v in zip(t3d, v3d) if t_start <= t <= t_end]

ax1.plot(t2d_ov, v2d_ov, color="#1f77b4", lw=1.8, label="STOFS-2D-Global (LMSL, OPeNDAP, ~hourly)")
ax1.plot(t3d_ov, v3d_ov, color="#d62728", lw=1.2, alpha=0.85, label="STOFS-3D-Atlantic (NAVD88, S3, 6-min)")
ax1.axhline(0, color="gray", lw=0.6, ls="--")
ax1.set_ylabel("Water Level (m)", fontsize=10)
ax1.set_title("Overlap Period (both models)", fontsize=10)
ax1.legend(fontsize=8.5, loc="upper right")
ax1.xaxis.set_major_formatter(mdates.DateFormatter("%b %d\n%Hz"))
ax1.xaxis.set_major_locator(mdates.HourLocator(byhour=[0, 6, 12, 18]))
ax1.grid(True, alpha=0.3)
ax1.set_xlim(t_start, t_end)

# ── Panel 2: full 2D-Global forecast (7.5-day) ──────────────────────────────
ax2 = axes[1]
ax2.plot(t2d, v2d, color="#1f77b4", lw=1.5, label="STOFS-2D-Global (cycle 2026-02-19 06z, 181 pts)")
ax2.fill_between(t2d, v2d, alpha=0.12, color="#1f77b4")
ax2.axhline(0, color="gray", lw=0.6, ls="--")
# Mark overlap region
ax2.axvspan(t_start, t_end, alpha=0.08, color="red", label="3D-Atlantic overlap window")
ax2.set_ylabel("Water Level (m)", fontsize=10)
ax2.set_title("STOFS-2D-Global Full Forecast (7.5 days)", fontsize=10)
ax2.legend(fontsize=8.5, loc="upper right")
ax2.xaxis.set_major_formatter(mdates.DateFormatter("%b %d"))
ax2.xaxis.set_major_locator(mdates.DayLocator())
ax2.grid(True, alpha=0.3)

# ── Metadata box ────────────────────────────────────────────────────────────
